let API_URL = 'https://provedordoc-1.onrender.com';
// Durante desenvolvimento local, apontar para o backend Python em execução localmente
// O backend convertido no workspace usa padrão na porta 5000.
if (process.env.NODE_ENV === 'development') {
	API_URL = 'http://localhost:5000';
}
export default API_URL;
